     6→import fp from 'fastify-plugin';
     7→import { FastifyInstance } from 'fastify';
     8→import { createProctoringRoomService } from './room.service';
     9→import { authMiddleware } from '../../middleware/auth.middleware';
    10→import type {
    11→  CreateRoomRequest,
    12→  CreateRoomResponse,
    13→  JoinRoomResponse,
    14→  ActiveRoomsResponse,
    15→  CloseRoomResponse
    16→} from './room.schema';
    17→
    18→// ============================================================================
    19→// Routes Plugin
    20→// ============================================================================
    21→
    22→export default fp(async (fastify: FastifyInstance) => {
    23→  const roomService = createProctoringRoomService(fastify.pg as any);
    24→
    25→  // ==========================================================================
    26→  // POST /api/room/create - Create a new proctoring room
    27→  // ==========================================================================
    28→
    29→  fastify.post('/api/room/create', {
    30→    onRequest: [authMiddleware],
    31→    schema: {
    32→      body: {
    33→        type: 'object',
    34→        properties: {
    35→          examId: { type: 'number' }
    36→        },
    37→        required: ['examId']
    38→      }
    39→    },
    40→    handler: async (request, reply): Promise<CreateRoomResponse> => {
    41→      // @ts-ignore
    42→      const teacherId = request.user.id;
    43→      const body = request.body as CreateRoomRequest;
    44→
    45→      try {
    46→        const room = await roomService.createRoom({
    47→          examId: body.examId,
    48→          teacherId
    49→        });
    50→
    51→        // Get exam details for response
    52→        const examResult = await fastify.pg.query(
    53→          'SELECT exam_name, course_name FROM exams WHERE id = $1',
    54→          [room.exam_id]
    55→        );
    56→
    57→        const exam = examResult.rows[0];
    58→
    59→        return {
    60→          success: true,
    61→          data: {
    62→            roomId: room.id,
    63→            roomCode: room.room_code,
    64→            inviteLink: `proctor://room/${room.room_code}`,
    65→            examName: exam.exam_name,
    66→            courseName: exam.course_name
    67→          }
    68→        };
    69→      } catch (error) {
    70→        if ((error as Error).name === 'ExamNotFoundError') {
    71→          return reply.code(404).send({
    72→            success: false,
    73→            error: 'Exam not found'
    74→          });
    75→        }
    76→
    77→        if ((error as Error).name === 'NotEnrolledError') {
